class Solution:
    def getMinDistSum(self, positions):
        n = len(positions)
        x = sum(p[0] for p in positions) / n
        y = sum(p[1] for p in positions) / n
        for _ in range(200):
            num_x = num_y = den = 0.0
            for px, py in positions:
                d = ((px - x) ** 2 + (py - y) ** 2) ** 0.5
                if d < 1e-9:
                    d = 1e-9
                num_x += px / d
                num_y += py / d
                den += 1 / d
            x, y = num_x / den, num_y / den
        return sum(((px - x) ** 2 + (py - y) ** 2) ** 0.5 for px, py in positions)

