var getMinDistSum = function(positions) {
    const n = positions.length;
    let x = positions.reduce((a, p) => a + p[0], 0) / n;
    let y = positions.reduce((a, p) => a + p[1], 0) / n;
    for (let it = 0; it < 200; it++) {
        let numX = 0, numY = 0, den = 0;
        for (const [px, py] of positions) {
            let d = Math.sqrt((px - x) ** 2 + (py - y) ** 2);
            if (d < 1e-9) d = 1e-9;
            numX += px / d;
            numY += py / d;
            den += 1 / d;
        }
        x = numX / den;
        y = numY / den;
    }
    let total = 0;
    for (const [px, py] of positions) total += Math.sqrt((px - x) ** 2 + (py - y) ** 2);
    return total;
};
